mapper.select:
SELECT budget_id, project_id, category, description, amount, used_by, used_at, created_at
FROM budget
WHERE project_id = #{projectId}
  AND budget_id = #{budgetId}

mapper.update:
UPDATE budget
SET category    = #{category},
    description = #{description},
    amount      = #{amount},
    used_at     = #{usedAt}
WHERE budget_id = #{budgetId}
  AND project_id = #{projectId}

mapper.delete:
DELETE FROM budget
WHERE budget_id = #{budgetId}
  AND project_id = #{projectId}
